-- PHARMACY DATASET V15.0 - STRICT CONSTRAINTS
CREATE DATABASE IF NOT EXISTS pharmacy_v15;
USE pharmacy_v15;

SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `stock_movements`, `invoice_details`, `invoices`, `inventory`, `pharmacists`, `customers`, `batches`, `medicines`, `categories`, `branches`;
SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE `categories` (
  `category_id` INT PRIMARY KEY AUTO_INCREMENT,
  `category_name` VARCHAR(100) NOT NULL
);

CREATE TABLE `medicines` (
  `medicine_id` INT PRIMARY KEY AUTO_INCREMENT,
  `category_id` INT NOT NULL,
  `name` VARCHAR(255) NOT NULL,
  `brand` VARCHAR(100),
  `base_unit` VARCHAR(50) DEFAULT 'Hộp',
  `sub_unit` VARCHAR(50) DEFAULT 'Viên',
  `conversion_rate` INT NOT NULL DEFAULT 1,
  `base_sell_price` INT NOT NULL,
  `sub_sell_price` INT NOT NULL,
  `min_stock_level` INT UNSIGNED DEFAULT 50,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (`category_id`) REFERENCES `categories`(`category_id`) ON DELETE RESTRICT
);

CREATE TABLE `batches` (
  `batch_id` INT PRIMARY KEY AUTO_INCREMENT,
  `medicine_id` INT NOT NULL,
  `batch_number` VARCHAR(50) NOT NULL,
  `manufacturing_date` DATE,
  `expiry_date` DATE NOT NULL,
  `import_price_package` INT NOT NULL,
  `current_total_quantity` INT UNSIGNED NOT NULL,
  `import_date` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT `chk_expiry` CHECK (`expiry_date` > `manufacturing_date`),
  FOREIGN KEY (`medicine_id`) REFERENCES `medicines`(`medicine_id`) ON DELETE RESTRICT
);

CREATE TABLE `branches` (
  `branch_id` INT PRIMARY KEY AUTO_INCREMENT,
  `branch_name` VARCHAR(100) NOT NULL,
  `address` VARCHAR(255),
  `phone_number` VARCHAR(20)
);

CREATE TABLE `inventory` (
  `inventory_id` INT PRIMARY KEY AUTO_INCREMENT,
  `branch_id` INT NOT NULL,
  `batch_id` INT NOT NULL,
  `quantity_std` INT UNSIGNED NOT NULL DEFAULT 0,
  `last_updated` TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  UNIQUE KEY `idx_branch_batch` (`branch_id`, `batch_id`),
  CONSTRAINT `chk_qty` CHECK (`quantity_std` >= 0),
  FOREIGN KEY (`branch_id`) REFERENCES `branches`(`branch_id`) ON DELETE RESTRICT,
  FOREIGN KEY (`batch_id`) REFERENCES `batches`(`batch_id`) ON DELETE RESTRICT
);

CREATE TABLE `pharmacists` (
  `pharmacist_id` INT PRIMARY KEY AUTO_INCREMENT,
  `branch_id` INT NOT NULL,
  `username` VARCHAR(50) UNIQUE NOT NULL,
  `password` VARCHAR(255) NOT NULL,
  `full_name` VARCHAR(100),
  `role` VARCHAR(50) DEFAULT 'STAFF',
  FOREIGN KEY (`branch_id`) REFERENCES `branches`(`branch_id`) ON DELETE RESTRICT
);

CREATE TABLE `customers` (
  `customer_id` INT PRIMARY KEY AUTO_INCREMENT,
  `phone_number` VARCHAR(20) UNIQUE NOT NULL,
  `customer_name` VARCHAR(100),
  `points` INT UNSIGNED DEFAULT 0
);

CREATE TABLE `invoices` (
  `invoice_id` INT PRIMARY KEY AUTO_INCREMENT,
  `invoice_date` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  `branch_id` INT NOT NULL,
  `pharmacist_id` INT NOT NULL,
  `customer_id` INT NULL,
  `sub_total` INT NOT NULL,
  `discount_amount` INT NOT NULL DEFAULT 0,
  `total_amount` INT NOT NULL,
  `points_redeemed` INT UNSIGNED DEFAULT 0,
  `points_earned` INT UNSIGNED DEFAULT 0,
  `is_simulated` BOOLEAN DEFAULT FALSE,
  FOREIGN KEY (`branch_id`) REFERENCES `branches`(`branch_id`) ON DELETE RESTRICT,
  FOREIGN KEY (`pharmacist_id`) REFERENCES `pharmacists`(`pharmacist_id`) ON DELETE RESTRICT,
  FOREIGN KEY (`customer_id`) REFERENCES `customers`(`customer_id`) ON DELETE RESTRICT
);

CREATE TABLE `invoice_details` (
  `detail_id` INT PRIMARY KEY AUTO_INCREMENT,
  `invoice_id` INT NOT NULL,
  `batch_id` INT NOT NULL,
  `quantity_sold` INT UNSIGNED NOT NULL,
  `unit_price` DECIMAL(12, 2) NOT NULL,
  FOREIGN KEY (`invoice_id`) REFERENCES `invoices`(`invoice_id`) ON DELETE RESTRICT,
  FOREIGN KEY (`batch_id`) REFERENCES `batches`(`batch_id`) ON DELETE RESTRICT
);

CREATE TABLE `stock_movements` (
  `movement_id` INT PRIMARY KEY AUTO_INCREMENT,
  `inventory_id` INT NOT NULL,
  `type` ENUM('BÁN HÀNG', 'NHẬP HÀNG', 'ĐIỀU CHỈNH') NOT NULL,
  `quantity_change` INT NOT NULL,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (`inventory_id`) REFERENCES `inventory`(`inventory_id`) ON DELETE RESTRICT
);

